/**
 * @param {number[][]} points
 * @param {number[]} target
 * @return {number}
 */
function solve(points, target) {
    // Helper to convert a point array [x, y, z] to a string key for Set usage
    const pointToKey = (p) => `${p[0]},${p[1]},${p[2]}`;

    // Initial set of points (using string keys for efficient lookup)
    let currentPointsSet = new Set();
    for (const point of points) {
        currentPointsSet.add(pointToKey(point));
    }

    // Check for k=0
    const targetKey = pointToKey(target);
    if (currentPointsSet.has(targetKey)) {
        return 0;
    }

    // List of points generated so far (needed for generating next generation)
    // We store the actual arrays/objects for easier calculations, though the set is used for tracking uniqueness.
    let currentPointsList = points.map(p => [...p]);

    let k = 0;
    const maxK = 100000; // Safety break, although constraints suggest a smaller bound might suffice

    while (k < maxK) {
        k++;
        const nextGenerationPoints = new Set();
        const newPointsList = [];

        // Collect all points from generations 0 up to k-1
        // Since currentPointsList holds all points generated up to generation k-1, we iterate over it.
        // The problem states: "Consider all points extracted from generation 0 to k-1".
        // We maintain currentPointsList to hold all unique points found so far.

        const pointsToConsider = currentPointsList;
        const n = pointsToConsider.length;

        // Generate new points (k-th generation)
        for (let i = 0; i < n; i++) {
            for (let j = i + 1; j < n; j++) {
                const p1 = pointsToConsider[i];
                const p2 = pointsToConsider[j];

                // Check the condition: "two different points"
                // Since we iterate j = i+1, the points in the list might have the same coordinates
                // if they were added redundantly, but the problem implies we only need to check
                // if the coordinates are different.

                // The crucial constraint is: "two different points" meaning distinct coordinates.
                // If two points in pointsToConsider have the exact same coordinates, we should not pair them.
                // However, currentPointsList should ideally only contain unique coordinate points if we manage it properly.
                // Let's rely on the Set structure to ensure we only process unique coordinate points for pairing.

                // Since pointsToConsider is built from the list of *unique* points found so far (conceptually),
                // we just need to ensure p1 != p2 based on coordinates.

                const coordsEqual = p1[0] === p2[0] && p1[1] === p2[1] && p1[2] === p2[2];
                if (coordsEqual) {
                    // This should ideally not happen if currentPointsList is managed correctly based on unique coordinates.
                    continue;
                }

                // Calculate c = [floor((x1 + x2) / 2), floor((y1 + y2) / 2), floor((z1 + z2) / 2)]
                const c = [
                    Math.floor((p1[0] + p2[0]) / 2),
                    Math.floor((p1[1] + p2[1]) / 2),
                    Math.floor((p1[2] + p2[2]) / 2)
                ];

                const cKey = pointToKey(c);

                if (!nextGenerationPoints.has(cKey)) {
                    nextGenerationPoints.add(cKey);
                    newPointsList.push(c);
                }
            }
        }

        // Check if the target is in the newly generated points of generation k
        for (const newPoint of newPointsList) {
            if (newPoint[0] === target[0] && newPoint[1] === target[1] && newPoint[2] === target[2]) {
                return k;
            }
        }

        // Update the list of all known points (points from Gen 0 to Gen k)
        // We only add points that were newly generated in this step (newPointsList)
        currentPointsList.push(...newPointsList);
    }

    // If the loop finishes without finding the target
    return -1;
}

